  snowflake: <DatabaseOutlined />,
  unity_catalog: <ThunderboltOutlined />,
  adls_gen2: <CloudOutlined />,
  s3: <CloudOutlined />,
  iceberg: <GoldOutlined />,
  other: <FileOutlined />,
};

