1	import type { AssetSummary } from '../../api/assets';
2	
3	/**
4	 * Hierarchical asset browse (#802) — pure, so it can be unit-tested without
5	 * rendering antd (kept out of the `.tsx` so the Tree component can fast-refresh).
6	 *
7	 * This is a **presentation regrouping**, not a new identity: assets stay keyed by
8	 * the ADR 0034 OpenLineage `namespace` + `name`, which already encode the
9	 * datasource root and the dotted/slashed path down to the leaf. We derive the
10	 * tree straight from those strings:
11	 *
12	 * - **root** = the OL `namespace` (the datasource instance — Snowflake account,
13	 *   UC workspace, ADLS container, S3 bucket, Iceberg catalog). Assets are
14	 *   connection-*agnostic* by ADR 0034 (the same physical table reached via two
15	 *   connections is one asset), so the namespace is the honest "connection root".
16	 * - **middle + leaf** = the `name` split into segments. Warehouse names are
17	 *   dotted (`DB.SCHEMA.TABLE`); flat-file names are slashed paths
18	 *   (`raw/orders/2024.csv`). The last segment is the asset (a selectable leaf);
19	 *   the earlier segments are the database/catalog → schema/namespace folders,
20	 *   merged across assets that share a prefix.
21	 *
22	 * A node can be *both* a folder and a selectable asset — a flat-file `raw/orders`
23	 * leaf can coexist with `raw/orders/2024.csv` under it — so `asset` and
24	 * `children` are independent.
25	 */
26	
27	export type DatasourceKind =
28	  'snowflake' | 'unity_catalog' | 'adls_gen2' | 's3' | 'iceberg' | 'other';
29	
30	export interface AssetTreeNode {
31	  /** Stable, unique key: the full `ns::{namespace}/seg/seg…` path. */
32	  key: string;
33	  /** The segment label (a namespace on roots, one path segment otherwise). */
34	  label: string;
35	  /** Datasource kind — set on root (namespace) nodes only, for the icon. */
36	  kind?: DatasourceKind;
37	  /** The asset — set on leaf (and folder-leaf) nodes; makes the node openable. */
38	  asset?: AssetSummary;
39	  children: AssetTreeNode[];
40	}
41	
42	/** Classify an OL namespace by its scheme, for the root-node icon/label. */
43	export function datasourceKind(namespace: string): DatasourceKind {
44	  if (namespace.startsWith('snowflake://')) return 'snowflake';
45	  if (namespace.startsWith('unitycatalog://')) return 'unity_catalog';
46	  if (namespace.startsWith('abfss://')) return 'adls_gen2';
47	  if (namespace.startsWith('s3://')) return 's3';
48	  // Iceberg namespaces are the raw catalog_uri (thrift://…, http://…, "file") —
49	  // no single stable scheme, so everything unrecognised falls here.
50	  return 'other';
51	}
52	
53	/**
54	 * Split an asset `name` into its hierarchy segments. Slashed names (flat-file
55	 * paths) split on `/`; everything else (dotted warehouse/UC/Iceberg names) on
56	 * `.`. Empty segments are dropped; a name that reduces to nothing falls back to
57	 * the whole name so an asset always has at least one (leaf) segment.
58	 */
59	export function nameSegments(name: string): string[] {
60	  const sep = name.includes('/') ? '/' : '.';
61	  const parts = name.split(sep).filter((s) => s.length > 0);
62	  return parts.length > 0 ? parts : [name];
63	}
64	
65	interface MutableNode {
66	  key: string;
67	  label: string;
68	  kind?: DatasourceKind;
69	  asset?: AssetSummary;
70	  children: Map<string, MutableNode>;
71	}
72	
73	function freeze(node: MutableNode): AssetTreeNode {
74	  return {
75	    key: node.key,
76	    label: node.label,
77	    ...(node.kind ? { kind: node.kind } : {}),
78	    ...(node.asset ? { asset: node.asset } : {}),
79	    children: [...node.children.values()]
80	      .map(freeze)
81	      .sort((a, b) => a.label.localeCompare(b.label)),
82	  };
83	}
84	
85	/**
86	 * Build the connection-rooted asset tree from a flat asset list. Roots are
87	 * sorted by namespace, children by label, both case-insensitively; the shape is
88	 * deterministic for a given input (test-friendly, no render churn).
89	 */
90	export function buildAssetTree(assets: AssetSummary[]): AssetTreeNode[] {
91	  const roots = new Map<string, MutableNode>();
92	  for (const asset of assets) {
93	    const rootKey = `ns::${asset.namespace}`;
94	    let node = roots.get(rootKey);
95	    if (!node) {
96	      node = {
97	        key: rootKey,
98	        label: asset.namespace,
99	        kind: datasourceKind(asset.namespace),
100	        children: new Map(),
101	      };
102	      roots.set(rootKey, node);
103	    }
104	    const segments = nameSegments(asset.name);
105	    let cursor: MutableNode = node;
106	    let path = rootKey;
107	    segments.forEach((segment, i) => {
108	      path += `/${segment}`;
109	      let child = cursor.children.get(segment);
110	      if (!child) {
111	        child = { key: path, label: segment, children: new Map() };
112	        cursor.children.set(segment, child);
113	      }
114	      cursor = child;
115	      // The final segment is the asset itself — attach it (a node can already
116	      // have children from a longer sibling path, so this merges, not replaces).
117	      if (i === segments.length - 1) cursor.asset = asset;
118	    });
119	  }
120	  return [...roots.values()].map(freeze).sort((a, b) => a.label.localeCompare(b.label));
121	}
122	
123	/** Every node key that has descendants — the default-expanded set (roots + folders). */
124	export function expandableKeys(nodes: AssetTreeNode[]): string[] {
125	  const keys: string[] = [];
126	  const walk = (list: AssetTreeNode[]) => {
127	    for (const n of list) {
128	      if (n.children.length > 0) {
129	        keys.push(n.key);
130	        walk(n.children);
131	      }
132	    }
133	  };
134	  walk(nodes);
135	  return keys;
136	}

1	import { describe, expect, it } from 'vitest';
2	
3	import type { AssetSummary } from '../../src/api/assets';
4	import {
5	  buildAssetTree,
6	  datasourceKind,
7	  expandableKeys,
8	  nameSegments,
9	} from '../../src/components/assets/assetTree';
10	
11	// A minimal asset factory — the tree only reads id/namespace/name/env, but the
12	// leaf carries the whole summary so the UI can render its health tag.
13	function asset(
14	  over: Partial<AssetSummary> & Pick<AssetSummary, 'id' | 'namespace' | 'name'>,
15	): AssetSummary {
16	  return {
17	    env: null,
18	    description: null,
19	    owner_user_id: null,
20	    last_seen: '2026-07-01T10:00:00Z',
21	    suite_count: 1,
22	    worst_severity: null,
23	    checks_total: 0,
24	    checks_passed: 0,
25	    last_run_at: null,
26	    has_failed_run: false,
27	    has_active_run: false,
28	    ...over,
29	  };
30	}
31	
32	describe('datasourceKind', () => {
33	  it('classifies each OL namespace scheme, unknown → other', () => {
34	    expect(datasourceKind('snowflake://acct')).toBe('snowflake');
35	    expect(datasourceKind('unitycatalog://host')).toBe('unity_catalog');
36	    expect(datasourceKind('abfss://c@a.dfs.core.windows.net')).toBe('adls_gen2');
37	    expect(datasourceKind('s3://bucket')).toBe('s3');
38	    expect(datasourceKind('thrift://iceberg:9083')).toBe('other');
39	    expect(datasourceKind('file')).toBe('other');
40	  });
41	});
42	
43	describe('nameSegments', () => {
44	  it('splits dotted warehouse names', () => {
45	    expect(nameSegments('ANALYTICS.PUBLIC.ORDERS')).toEqual(['ANALYTICS', 'PUBLIC', 'ORDERS']);
46	  });
47	  it('splits slashed flat-file paths', () => {
48	    expect(nameSegments('raw/orders/2024.csv')).toEqual(['raw', 'orders', '2024.csv']);
49	  });
50	  it('drops empty segments and never returns nothing', () => {
51	    expect(nameSegments('raw/orders/')).toEqual(['raw', 'orders']);
52	    expect(nameSegments('.')).toEqual(['.']); // pathological → whole name as one leaf
53	  });
54	});
55	
56	describe('buildAssetTree', () => {
57	  it('roots by namespace and nests db → schema → table, leaf carries the asset', () => {
58	    const a = asset({ id: 'a1', namespace: 'snowflake://acct', name: 'ANALYTICS.PUBLIC.ORDERS' });
59	    const [root] = buildAssetTree([a]);
60	    expect(root.label).toBe('snowflake://acct');
61	    expect(root.kind).toBe('snowflake');
62	    expect(root.asset).toBeUndefined();
63	    const db = root.children[0];
64	    expect(db.label).toBe('ANALYTICS');
65	    const schema = db.children[0];
66	    expect(schema.label).toBe('PUBLIC');
67	    const table = schema.children[0];
68	    expect(table.label).toBe('ORDERS');
69	    expect(table.asset).toBe(a);
70	    expect(table.children).toEqual([]);
71	  });
72	
73	  it('merges assets that share a namespace/schema prefix', () => {
74	    const orders = asset({ id: 'a1', namespace: 'snowflake://acct', name: 'DB.S.ORDERS' });
75	    const customers = asset({ id: 'a2', namespace: 'snowflake://acct', name: 'DB.S.CUSTOMERS' });
76	    const roots = buildAssetTree([orders, customers]);
77	    expect(roots).toHaveLength(1); // one namespace root
78	    const schema = roots[0].children[0].children[0];
79	    // Two tables under the shared DB.S schema, sorted by label.
80	    expect(schema.children.map((c) => c.label)).toEqual(['CUSTOMERS', 'ORDERS']);
81	  });
82	
83	  it('keeps distinct namespaces as separate roots (env distinctness, ADR 0034)', () => {
84	    const dev = asset({ id: 'a1', namespace: 'snowflake://dev', name: 'DB.S.T', env: 'dev' });
85	    const qa = asset({ id: 'a2', namespace: 'snowflake://qa', name: 'DB.S.T', env: 'qa' });
86	    const roots = buildAssetTree([dev, qa]);
87	    expect(roots.map((r) => r.label)).toEqual(['snowflake://dev', 'snowflake://qa']);
88	  });
89	
90	  it('handles a folder-and-leaf collision (a path that is both)', () => {
91	    const dir = asset({ id: 'a1', namespace: 's3://b', name: 'raw/orders' });
92	    const file = asset({ id: 'a2', namespace: 's3://b', name: 'raw/orders/2024.csv' });
93	    const [root] = buildAssetTree([dir, file]);
94	    const raw = root.children[0];
95	    const orders = raw.children[0];
96	    expect(orders.label).toBe('orders');
97	    expect(orders.asset).toBe(dir); // selectable as its own asset…
98	    expect(orders.children[0].asset).toBe(file); // …and a folder for the file below
99	  });
100	});
101	
102	describe('expandableKeys', () => {
103	  it('returns roots + folders but not leaves', () => {
104	    const a = asset({ id: 'a1', namespace: 'snowflake://acct', name: 'DB.S.T' });
105	    const tree = buildAssetTree([a]);
106	    const keys = expandableKeys(tree);
107	    // root, DB, S are expandable; the leaf T is not.
108	    expect(keys).toContain('ns::snowflake://acct');
109	    expect(keys).toContain('ns::snowflake://acct/DB');
110	    expect(keys).toContain('ns::snowflake://acct/DB/S');
111	    expect(keys).not.toContain('ns::snowflake://acct/DB/S/T');
